def build_detection_agent_v2_prompt(chunk_size: int) -> str:
    return DETECTION_AGENT_V2_PROMPT_TEMPLATE.format(chunk_size=chunk_size).strip()


def build_detection_agent_v3_prompt(chunk_size: int, mode: str) -> str:
    if mode == "train-combined-fn":
        template = DETECTION_AGENT_V3_COMBINED_FN_PROMPT_TEMPLATE
    elif mode == "train-combined-fp":
        template = DETECTION_AGENT_V3_COMBINED_FP_PROMPT_TEMPLATE
    elif mode == "train-LLM-only-image":
        template = DETECTION_AGENT_V3_IMAGE_PROMPT_TEMPLATE
    else:
        template = DETECTION_AGENT_V3_DEFAULT_PROMPT_TEMPLATE
    return template.format(chunk_size=chunk_size).strip()
